function renderContinents(){$.ajax({type:"GET",url:"/League/ContinentJson",cache:!1,beforeSend:function(){$("#divLoading").show()},success:function(n){$("#divContinents").empty();$("#divContinents").append($.render.continentTemplate(n));$("#divLoading").hide()},error:function(){$("#divLoading").hide();PreOdds.Utils.ShowErrorNotification("İşleminiz sırasında bir hata oluştu, lütfen daha sonra tekrar deneyin.")}})}function renderLeagues(n){var t="#checkbox_"+n;if($(t).prop("checked")==!1)return $("#divLeagues_"+n).empty(),document.getElementById("checkbox_"+n).checked=!1,!1;$.ajax({type:"GET",url:"/League/LeaguesJson",data:{countryId:n},cache:!1,beforeSend:function(){},success:function(t){$("#divLeagues_"+n).empty();$("#divLeagues_"+n).append($.render.leaguesTemplate(t));document.getElementById("checkbox_"+n).checked=!0},error:function(){$("#divLoading").hide();PreOdds.Utils.ShowErrorNotification("İşleminiz sırasında bir hata oluştu, lütfen daha sonra tekrar deneyin.")}})}$.templates("continentTemplate",{markup:"#continentTemplate",templates:{leaguesTemplate:"#leaguesTemplate"}});$(document).ready(function(){renderContinents()});